    34→    docs: {
    35→      description:
    36→        'Disallow type assertions that do not change the type of an expression',
    37→      recommended: 'recommended',
    38→      requiresTypeChecking: true,
    39→    },
    40→    fixable: 'code',
    41→    messages: {
    42→      contextuallyUnnecessary:
    43→        'This assertion is unnecessary since the receiver accepts the original type of the expression.',
    44→      unnecessaryAssertion:
