     2→import * as tsutils from 'ts-api-utils';
     3→import * as ts from 'typescript';
     4→
     5→import { isTypeFlagSet } from './typeFlagUtils';
     6→
     7→const log = debug('typescript-eslint:type-utils:predicates');
     8→
     9→/**
    10→ * Checks if the given type is (or accepts) nullable
    11→ */
    12→export function isNullableType(type: ts.Type): boolean {
    13→  return isTypeFlagSet(
    14→    type,
    15→    ts.TypeFlags.Any |
    16→      ts.TypeFlags.Unknown |
    17→      ts.TypeFlags.Null |
    18→      ts.TypeFlags.Undefined |
    19→      ts.TypeFlags.Void,
    20→  );
    21→}
    22→
    23→/**
    24→ * Checks if the given type is either an array type,
    25→ * or a union made up solely of array types.
    26→ */
    27→export function isTypeArrayTypeOrUnionOfArrayTypes(
    28→  type: ts.Type,
    29→  checker: ts.TypeChecker,
    30→): boolean {
    31→  for (const t of tsutils.unionConstituents(type)) {
    32→    if (!checker.isArrayType(t)) {
    33→      return false;
    34→    }
    35→  }
    36→
    37→  return true;
    38→}
    39→
    40→/**
    41→ * @returns true if the type is `never`
    42→ */
    43→export function isTypeNeverType(type: ts.Type): boolean {
    44→  return isTypeFlagSet(type, ts.TypeFlags.Never);
    45→}
    46→
    47→/**
    48→ * @returns true if the type is `unknown`
    49→ */
    50→export function isTypeUnknownType(type: ts.Type): boolean {
    51→  return isTypeFlagSet(type, ts.TypeFlags.Unknown);
    52→}
    53→
    54→// https://github.com/microsoft/TypeScript/blob/42aa18bf442c4df147e30deaf27261a41cbdc617/src/compiler/types.ts#L5157
    55→const Nullable = ts.TypeFlags.Undefined | ts.TypeFlags.Null;
    56→// https://github.com/microsoft/TypeScript/blob/42aa18bf442c4df147e30deaf27261a41cbdc617/src/compiler/types.ts#L5187
    57→const ObjectFlagsType =
    58→  ts.TypeFlags.Any |
    59→  Nullable |
    60→  ts.TypeFlags.Never |
    61→  ts.TypeFlags.Object |
    62→  ts.TypeFlags.Union |
    63→  ts.TypeFlags.Intersection;
    64→export function isTypeReferenceType(type: ts.Type): type is ts.TypeReference {
    65→  if ((type.flags & ObjectFlagsType) === 0) {
    66→    return false;
    67→  }
    68→  const objectTypeFlags = (type as ts.ObjectType).objectFlags;
    69→  return (objectTypeFlags & ts.ObjectFlags.Reference) !== 0;
    70→}
    71→
    72→/**
    73→ * @returns true if the type is `any`
    74→ */
    75→export function isTypeAnyType(type: ts.Type): boolean {
    76→  if (isTypeFlagSet(type, ts.TypeFlags.Any)) {
    77→    if (type.intrinsicName === 'error') {
    78→      log('Found an "error" any type');
    79→    }
    80→    return true;
    81→  }
    82→  return false;
    83→}
    84→
    85→/**
    86→ * @returns true if the type is `any[]`
    87→ */
    88→export function isTypeAnyArrayType(
    89→  type: ts.Type,
    90→  checker: ts.TypeChecker,
    91→): boolean {
    92→  return (
    93→    checker.isArrayType(type) &&
    94→    isTypeAnyType(checker.getTypeArguments(type)[0])
    95→  );
    96→}
    97→
    98→/**
    99→ * @returns true if the type is `unknown[]`
   100→ */
   101→export function isTypeUnknownArrayType(
   102→  type: ts.Type,
   103→  checker: ts.TypeChecker,
   104→): boolean {
   105→  return (
   106→    checker.isArrayType(type) &&
   107→    isTypeUnknownType(checker.getTypeArguments(type)[0])
   108→  );
   109→}
   110→
   111→/**
   112→ * @returns Whether a type is an instance of the parent type, including for the parent's base types.
   113→ */
   114→export function typeIsOrHasBaseType(
   115→  type: ts.Type,
   116→  parentType: ts.Type,
   117→): boolean {
   118→  const parentSymbol = parentType.getSymbol();
   119→  if (!type.getSymbol() || !parentSymbol) {
   120→    return false;
   121→  }
   122→
   123→  const typeAndBaseTypes = [type];
   124→  const ancestorTypes = type.getBaseTypes();
   125→
   126→  if (ancestorTypes) {
   127→    typeAndBaseTypes.push(...ancestorTypes);
   128→  }
   129→
   130→  for (const baseType of typeAndBaseTypes) {
   131→    const baseSymbol = baseType.getSymbol();
   132→    if (baseSymbol?.name === parentSymbol.name) {
   133→      return true;
   134→    }
   135→  }
   136→
   137→  return false;
   138→}
