import * as ts from 'typescript';

const code = `
declare function foo(): string | undefined;
function test() {
  const x = foo();
  if (x == null) return;
  const arr: string[] = [];
  arr.push(x!);
}

function test2() {
  let y = foo();
  if (y == null) return;
  const arr: string[] = [];
  const fn = () => { y = undefined; };
  arr.push(y!); // y is de-narrowed by closure
}
`;

const host = ts.createCompilerHost({
  strict: true,
  strictNullChecks: true,
});

const filename = '/tmp/test.ts';
const sourceFile = ts.createSourceFile(filename, code, ts.ScriptTarget.Latest, true);

const program = ts.createProgram({
  rootNames: [filename],
  options: { strictNullChecks: true, target: ts.ScriptTarget.Latest },
  host: {
    ...host,
    getSourceFile: (name, lang) => {
      if (name === filename) return sourceFile;
      return host.getSourceFile(name, lang);
    }
  }
});

const checker = program.getTypeChecker();

function visitNode(node: ts.Node) {
  if (ts.isNonNullExpression(node)) {
    const inner = node.expression;
    const type = checker.getTypeAtLocation(inner);
    const narrowed = checker.typeToString(type);
    const pos = inner.getStart();
    console.log(`NonNull expression at pos ${pos}: inner type = "${narrowed}"`);
  }
  ts.forEachChild(node, visitNode);
}

visitNode(sourceFile);
